// Moves mdBook's built-in controls out of the default #menu-bar and into the
// Breez brand header rendered by theme/header.hbs, so the whole design reads
// as a single top bar. The controls keep working because book.js binds its
// listeners to the elements themselves, not to their position.
//
// index.hbs is regenerated by mdbook-pagetoc on every build, so the header
// cannot be baked into it; this runs at load time instead. brand-header.js is
// listed last in additional-js, so book.js has already wired every control by
// the time this fires.
(function () {
    function relocate() {
        var header = document.getElementById("brand-header");
        var controls = document.getElementById("brand-controls");
        if (!header || !controls) {
            return;
        }
        // The sidebar toggle leads the bar, to the left of the logo, next to
        // the sidebar it controls. Search joins the right-hand controls. The
        // theme picker (#theme-toggle / #theme-list) is deliberately NOT
        // rescued from the hidden #menu-bar: the docs are pinned to the
        // "Auto" theme, which book.toml resolves to navy either way.
        var sidebarToggle = document.getElementById("sidebar-toggle");
        if (sidebarToggle) {
            header.insertBefore(sidebarToggle, header.firstChild);
        }
        ["search-toggle"].forEach(function (id) {
            var el = document.getElementById(id);
            if (el) {
                controls.appendChild(el);
            }
        });
        forceAutoTheme();
        markActiveNav();
        wireSidebarBehavior();
    }

    // The docs are pinned to the Auto theme: with no picker in the UI, a
    // visitor who chose a theme in the past would be stuck with it forever.
    // Wipe the stored choice and correct the current page load in place
    // (theme class + matching highlight stylesheet, mirroring book.js).
    function forceAutoTheme() {
        var stored = null;
        try {
            stored = localStorage.getItem("mdbook-theme");
            if (stored !== null) {
                localStorage.removeItem("mdbook-theme");
            }
        } catch (e) { }
        if (stored === null || stored === "navy") {
            return; // fresh visitors already resolve to navy via book.toml
        }
        var html = document.documentElement;
        ["light", "rust", "coal", "ayu"].forEach(function (cls) {
            html.classList.remove(cls);
        });
        html.classList.add("navy");
        var sheet = function (id) { return document.getElementById(id); };
        var hl = sheet("highlight-css");
        var tn = sheet("tomorrow-night-css");
        var ayu = sheet("ayu-highlight-css");
        if (hl) { hl.disabled = true; }
        if (tn) { tn.disabled = false; }
        if (ayu) { ayu.disabled = true; }
    }

    // Highlight the current top-level section link (Home / GitHub) when it matches.
    function markActiveNav() {
        var here = window.location.href;
        document.querySelectorAll("#brand-header .brand-nav a").forEach(function (a) {
            if (a.href && here.indexOf(a.href) === 0) {
                a.classList.add("is-active");
            }
        });
    }

    function wireSidebarBehavior() {
        var anchor = document.getElementById("sidebar-toggle-anchor");
        var sidebar = document.getElementById("sidebar");
        if (!anchor || !sidebar) {
            return;
        }

        function setSidebar(visible) {
            if (visible) {
                // book.js collapses the sidebar to display:none after the
                // hide transition; restore it before re-showing.
                sidebar.style.display = "";
                sidebar.offsetHeight; // force reflow so the transition runs
            }
            anchor.checked = visible;
            anchor.dispatchEvent(new Event("change", { bubbles: true }));
        }

        // mdBook hides the sidebar when the page loads in a narrow window but
        // never restores it when the window grows. If the user did not choose
        // to hide it (no localStorage verdict), bring it back on resize.
        var resizeTimer = null;
        window.addEventListener("resize", function () {
            clearTimeout(resizeTimer);
            resizeTimer = setTimeout(function () {
                if (window.innerWidth < 1080 || anchor.checked) {
                    return;
                }
                var stored = null;
                try { stored = localStorage.getItem("mdbook-sidebar"); } catch (e) { }
                if (stored !== "hidden") {
                    setSidebar(true);
                }
            }, 150);
        });

        // book.js's drag-resize only auto-hides below 20px, leaving an
        // illegible sliver on the way down. Hide as soon as the drag goes
        // under 200px instead (the CSS floors the rendered width at 200px,
        // so the content stays legible right up until it hides).
        var HIDE_BELOW = 200;
        window.addEventListener("mousemove", function (e) {
            if (!document.documentElement.classList.contains("sidebar-resizing")) {
                return;
            }
            var pos = e.clientX - sidebar.offsetLeft;
            if (pos < HIDE_BELOW && anchor.checked) {
                // End book.js's drag first so it stops fighting the hide.
                window.dispatchEvent(new MouseEvent("mouseup"));
                document.documentElement.style.setProperty("--sidebar-target-width", "312px");
                setSidebar(false);
            }
        });
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", relocate);
    } else {
        relocate();
    }
})();
